PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?carrier ?label
WHERE {
  wd:Q161393 wdt:P1605 ?carrier .
  OPTIONAL { ?carrier rdfs:label ?label . FILTER(LANG(?label) = 'en') }
}
LIMIT 10

